  end

  def process(%{category: :gamma, kind: :secondary} = data, opts) do
    with {:ok, ctx} <- context(opts[:context]), do: format(:gamma, data.status, ctx)
  end

  def process(%{category: :delta, kind: :primary} = data, opts) do
    with {:ok, ctx} <- context(opts[:context]), do: format(:delta, data.status, ctx)
  end

  def process(%{category: :delta, kind: :secondary} = data, opts) do
    with {:ok, ctx} <- context(opts[:context]), do: format(:delta, data.status, ctx)
  end

  def process(%{category: :epsilon, kind: :primary} = data, opts) do
