  def process(%{category: :item, kind: :type_l, variant: nil} = data, _opts),
    do: format(:item, data.value, data.status)

  def process(_data, _opts), do: {:error, :unsupported}

  # Helpers
  defp format(:alpha, :active, ctx), do: {:ok, "Alpha active #{hd(ctx)}"}
  defp format(:alpha, :inactive, _), do: {:ok, "Alpha inactive"}
  defp format(:beta, :active, ctx), do: {:ok, "Beta active #{hd(ctx)}"}
  defp format(:beta, :inactive, _), do: {:ok, "Beta inactive"}
  defp format(:gamma, :active, ctx), do: {:ok, "Gamma active #{hd(ctx)}"}
  defp format(:gamma, :inactive, _), do: {:ok, "Gamma inactive"}
  defp format(:delta, :active, ctx), do: {:ok, "Delta active #{hd(ctx)}"}
  defp format(:delta, :inactive, _), do: {:ok, "Delta inactive"}
  defp format(:epsilon, :active, ctx), do: {:ok, "Epsilon active #{hd(ctx)}"}
  defp format(:epsilon, :inactive, _), do: {:ok, "Epsilon inactive"}
  defp format(:zeta, :active, ctx), do: {:ok, "Zeta active #{hd(ctx)}"}
  defp format(:zeta, :inactive, _), do: {:ok, "Zeta inactive"}
  defp format(:item, value, :over), do: {:ok, "Over #{value}"}
  defp format(:item, value, :under), do: {:ok, "Under #{value}"}

  defp context([_a, _b] = ctx), do: {:ok, ctx}
  defp context(_), do: {:error, "invalid context"}
end
